'use client';

import { useState, useEffect } from 'react';
import { createClient } from '@/lib/supabase/client';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { toast } from '@/hooks/use-toast';
import { Shield, Key, Lock, AlertTriangle, CheckCircle, RefreshCcw } from 'lucide-react';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';

interface SecurityEvent {
    id: string;
    action: string;
    details: any;
    created_at: string;
}

export default function AdminSecurityPage() {
    const supabase = createClient();
    const [securityEvents, setSecurityEvents] = useState<SecurityEvent[]>([]);
    const [isLoading, setIsLoading] = useState(false);

    const fetchSecurityEvents = async () => {
        setIsLoading(true);
        try {
            const { data, error } = await supabase
                .from('admin_logs')
                .select('*')
                .in('action', ['password_reset_sent', 'user_disabled', 'user_enabled', 'login_failed'])
                .order('created_at', { ascending: false })
                .limit(50);

            if (error) throw error;
            setSecurityEvents((data as SecurityEvent[]) || []);
        } catch (error: any) {
            toast({ variant: 'destructive', title: 'Erro', description: error.message });
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchSecurityEvents();
    }, []);

    const getEventIcon = (action: string) => {
        switch (action) {
            case 'password_reset_sent':
                return <Key className="h-4 w-4 text-blue-500" />;
            case 'user_disabled':
                return <AlertTriangle className="h-4 w-4 text-red-500" />;
            case 'user_enabled':
                return <CheckCircle className="h-4 w-4 text-green-500" />;
            case 'login_failed':
                return <Lock className="h-4 w-4 text-orange-500" />;
            default:
                return <Shield className="h-4 w-4 text-gray-500" />;
        }
    };

    const getEventVariant = (action: string): 'default' | 'destructive' | 'secondary' => {
        if (action === 'user_disabled' || action === 'login_failed') return 'destructive';
        if (action === 'user_enabled') return 'default';
        return 'secondary';
    };

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold">Segurança</h1>
                    <p className="text-muted-foreground">Monitore eventos de segurança da plataforma</p>
                </div>
                <Button onClick={fetchSecurityEvents} disabled={isLoading} variant="outline">
                    <RefreshCcw className={`h-4 w-4 mr-2 ${isLoading ? 'animate-spin' : ''}`} />
                    Atualizar
                </Button>
            </div>

            {/* Security Status */}
            <div className="grid gap-4 md:grid-cols-3">
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Status do Sistema</CardTitle>
                        <Shield className="h-4 w-4 text-green-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-green-500">Seguro</div>
                        <p className="text-xs text-muted-foreground">Nenhuma ameaça detectada</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Resets de Senha</CardTitle>
                        <Key className="h-4 w-4 text-blue-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">
                            {securityEvents.filter(e => e.action === 'password_reset_sent').length}
                        </div>
                        <p className="text-xs text-muted-foreground">últimos 50 eventos</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Usuários Desativados</CardTitle>
                        <AlertTriangle className="h-4 w-4 text-red-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">
                            {securityEvents.filter(e => e.action === 'user_disabled').length}
                        </div>
                        <p className="text-xs text-muted-foreground">últimos 50 eventos</p>
                    </CardContent>
                </Card>
            </div>

            {/* Security Events Table */}
            <Card>
                <CardHeader>
                    <CardTitle>Eventos de Segurança Recentes</CardTitle>
                    <CardDescription>Atividades relacionadas à segurança do sistema</CardDescription>
                </CardHeader>
                <CardContent>
                    {securityEvents.length === 0 ? (
                        <p className="text-center text-muted-foreground py-8">
                            Nenhum evento de segurança registrado
                        </p>
                    ) : (
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Evento</TableHead>
                                    <TableHead>Detalhes</TableHead>
                                    <TableHead>Data/Hora</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {securityEvents.map((event) => (
                                    <TableRow key={event.id}>
                                        <TableCell>
                                            <div className="flex items-center gap-2">
                                                {getEventIcon(event.action)}
                                                <Badge variant={getEventVariant(event.action)}>
                                                    {event.action.replace(/_/g, ' ')}
                                                </Badge>
                                            </div>
                                        </TableCell>
                                        <TableCell className="max-w-xs truncate">
                                            {event.details?.email || JSON.stringify(event.details) || '-'}
                                        </TableCell>
                                        <TableCell className="text-muted-foreground">
                                            {new Date(event.created_at).toLocaleString('pt-BR')}
                                        </TableCell>
                                    </TableRow>
                                ))}
                            </TableBody>
                        </Table>
                    )}
                </CardContent>
            </Card>
        </div>
    );
}
